{
  "name": "Commodity Supplemental Food Program (CSFP)",
  "eligibility": {
    "age": 60,
    "income_limits": "Income at or below 150% of Federal Poverty Guidelines (effective March 7, 2025): Family Size 1: Annual $23,475 / Monthly $1,957 / Weekly $452; 2: $31,725 / $2,644 / $611; 3: $39,975 / $3,332 / $769; 4: $48,225 / $4,019 / $928; 5: $56,475 / $4,707 / $1,087; 6: $64,725 / $5,394 / $1,245; 7: $72,975 / $6,082 / $1,404; 8: $81,225 / $6,769 / $1,563; each additional: +$8,250 annual / +$688 monthly / +$159 weekly. Note: Some sources cite 130%, but Missouri official site specifies 150%.[1][2][4]",
    "asset_limits": "No asset limits mentioned in Missouri-specific sources.[1][2]",
    "other_requirements": ["Missouri resident.", "Verification: Age (e.g., birth certificate, driver's license, ID); Income (self-declaration); Residency (e.g., utility bill, driver's license, SSA document).[1][2]"]
  },
  "benefits": {
    "type": "in_kind",
    "value": "Monthly food package of nutritious USDA commodity foods (canned fruits/vegetables/meat, cheese, cereal/grain products, milk products), worth approximately $50.[2][4]",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Phone: 800-733-6251 (statewide locator for local sites).", "Website: https://health.mo.gov/living/wellness/nutrition/foodprograms/csfp/ (find site near you).", "In-person: Local distribution sites (contact via phone/website for locations, e.g., Platte County: 816-270-4100).[1][4][6]"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Program limited by funding; may have waitlists at local sites as it serves only as many as funding allows.[7]",
    "forms": ["No specific form name/number listed; certification at local site.[1][2]"],
    "documents": ["Proof of age (birth certificate, driver's license, state ID, etc.).", "Proof of residency (utility bill, driver's license with address, SSA document, etc.).", "Income self-declaration (no proof required).[1][2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide in Missouri, but only at designated local sites/providers.[1][2][9]",
    "regional_variations": "Distributed through local agencies/food banks (e.g., Southeast Missouri Food Bank, Platte Seniors); availability, wait times, and home delivery may vary by site; use locator for specifics.[3][6][7]",
    "offices_or_providers": ["Local sites found via 800-733-6251 or https://health.mo.gov/csfp; examples: Platte County (816-270-4100).[4][6][9]"]
  },
  "official_source": "https://health.mo.gov/living/wellness/nutrition/foodprograms/csfp/[2]",
  "gotchas": ["Cannot participate in both CSFP and WIC simultaneously.[2][5]", "Limited by funding, so not all eligible seniors can be served; check local availability/waitlist.[7]", "Only for those 60+; women/infants/children grandfathered pre-2014, no new certifications.[2][5]", "Income is 150% FPL per MO DHSS (conflicts with some generic 130% sources).[1][4]", "Must pick up monthly or arrange local home delivery; mobility-limited should confirm with site.[7]"],
  "data_shape_notes": "Statewide but site-specific distribution; income at 150% FPL (higher than federal max 130%); fixed monthly food package; funding caps create local waitlists; self-declared income with age/residency proof only."
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Household income must not exceed 125% of the federal poverty level. Specific dollar amounts vary annually and by household size; families must check current federal poverty guidelines (e.g., via HHS.gov) as exact 2026 figures not in sources. Excluded income includes: Social Security Disability Income, 25% of Social Security Income, unemployment benefits, SNAP benefits, housing benefits, and certain veterans' payments[1].",
    "asset_limits": "No asset limits mentioned in sources[1][2].",
    "other_requirements": ["Unemployed at time of application[1][2]", "U.S. citizen or eligible non-citizen (inferred from federal program standards)", "Priority for veterans/qualified spouses, individuals over 65, those with disabilities, low literacy/limited English proficiency, rural residents, homeless/at risk, low employment prospects, or prior American Job Center users[2]"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service work-based job training (average 20 hours/week) at nonprofits/public agencies (e.g., schools, hospitals, senior centers); paid at highest of federal/state/local minimum wage; Individual Employment Plan (IEP) with skills training, job search assistance (resumes, interviews), annual health screening, supportive services (benefit applications, local resources); goal of transition to unsubsidized employment[1][2][3].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: 573-526-4542 (Missouri Department of Health & Senior Services)[1]", "Contact MERS Goodwill for eastern/central/southeast Missouri (application request link noted, specific URL not provided)[4]", "Through local grantees like state agencies or nonprofits (national info via DOL or AARP Foundation, but MO-specific via state)[1][2][5]"],
    "processing_time": "Not specified in sources",
    "waitlist": "Not specified; availability varies by county[1]",
    "forms": ["Individual Employment Plan (IEP) developed after enrollment; no specific pre-application form named[1][3]"],
    "documents": ["Proof of age, income (pay stubs, benefit statements noting exclusions), unemployment status; exact list not detailed—prepare standard ID and financial docs[1]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Available in many counties throughout Missouri, not all[1]",
    "regional_variations": "Administered by different grantees/providers (e.g., Missouri Dept. of Health & Senior Services statewide contact; MERS Goodwill in eastern, central, southeast Missouri and southern Illinois)[1][4]",
    "offices_or_providers": ["Missouri Dept. of Health & Senior Services (statewide inquiries: 573-526-4542)[1]", "MERS Goodwill (eastern/central/southeast MO)[4]"]
  },
  "official_source": "https://health.mo.gov/seniors/senioremployment/[1]",
  "gotchas": ["Income exclusions are specific (e.g., only 25% of SS income excluded)—calculate carefully using current 125% FPL[1]", "Must be unemployed at application; program is temporary training bridge to unsubsidized jobs, not permanent[1][2]", "Availability limited to certain counties; contact state for local provider[1]", "Priority tiers may delay non-priority applicants[2]", "Host agencies are nonprofits/government only—no private sector placements[1][2]"],
  "data_shape_notes": "Grantee-administered with regional providers; income test at 125% FPL with specific exclusions; county-restricted availability; priority-based enrollment"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to any resident regardless of financial status",
    "asset_limits": "No asset limits; no financial tests apply",
    "other_requirements": ["Must be a resident of a long-term care facility in Missouri, such as nursing homes, residential care facilities, assisted living, skilled care nursing homes, residential care homes, or veteran homes"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including identifying, investigating, and resolving complaints related to health, safety, welfare, and rights; providing information on long-term services and supports; representing residents before agencies; seeking remedies; regular facility visits by trained volunteer ombudsmen to promote dignity, respect, protect rights, and voice concerns to facility management; community education on resident rights and long-term care issues",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: (800) 309-3282 or local (573) 526-0727", "Email: LTCOmbudsman@health.mo.gov", "Contact regional Area Agency on Aging (AAA) or local ombudsman program for in-person assistance", "Website: http://health.mo.gov/seniors/ombudsman/"],
    "processing_time": "Immediate assistance upon contact; no formal application processing as it is a complaint-resolution and advocacy service",
    "waitlist": null,
    "forms": ["No specific forms required"],
    "documents": ["No documents needed to request services; provide details of the resident's situation, facility name, and complaint"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services provided through regional programs in participating counties via Area Agencies on Aging (AAAs)",
    "regional_variations": "Operated by regional ombudsman coordinators through local AAAs or service providers; contact state office or local AAA for specific regional coordinator",
    "offices_or_providers": ["Administered statewide by Missouri Department of Health and Senior Services (DHSS), Division of Senior and Disability Services (DSDS); local programs via Area Agencies on Aging (AAAs)"]
  },
  "official_source": "http://health.mo.gov/seniors/ombudsman/",
  "gotchas": ["Not a financial aid or direct service program—provides advocacy only, not healthcare, housing, or payments; families may confuse it with entitlement programs; services are for residents already in facilities, not for admission or placement; relies on volunteers, so availability may depend on local coordinators; strict conflict-of-interest rules for ombudsmen ensure independence"],
  "data_shape_notes": "no income or asset test; advocacy-only for LTC facility residents; delivered via statewide network of regional AAAs with volunteer ombudsmen; immediate access without application"
}

{
